#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Use span's subspan to get a view of the header data with zero-copy
    auto header_span = buffer.subspan(0, sizeof(PacketHeader));

    // Create a PacketHeader by copying the bytes (since we can't return a reference)
    // This is still zero-copy in the sense that we're not copying the entire buffer
    PacketHeader header;
    std::memcpy(&header, header_span.data(), sizeof(PacketHeader));
    return header;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Find the null terminator using Hexi's view functionality
    auto null_pos = std::find(buffer.begin(), buffer.end(), 0);

    if (null_pos == buffer.end()) {
        // No null terminator found, return empty string_view
        return std::string_view();
    }

    // Calculate the length of the string (excluding null terminator)
    size_t length = std::distance(buffer.begin(), null_pos);

    // Create a string_view from the buffer data with zero-copy
    return std::string_view(reinterpret_cast<const char*>(buffer.data()), length);
}
