PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Ensure buffer is large enough for the header
    if (buffer.size() < sizeof(PacketHeader)) {
        throw std::runtime_error("Buffer too small for packet header");
    }

    // Use Hexi's span operations for zero-copy access
    auto header_view = buffer.first(sizeof(PacketHeader));

