std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Use Hexi's find operation to locate null terminator
    auto null_iterator = std::find(buffer.begin(), buffer.end(), 0);

    if (null_iterator == buffer.end()) {
        // Return empty view if no delimiter found
        return std::string_view();
    }

    // Calculate the size of the string (up to but not including null terminator)
    size_t message_size = std::distance(buffer.begin(), null_iterator);

