#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Return pointer to the beginning of the buffer for reading
    return buffer.empty() ? nullptr : buffer.data();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Return pointer to the beginning of the buffer for writing
    return buffer.empty() ? nullptr : buffer.data();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    BufferInfo info;

    // Readable size is the current size of the buffer
    info.readable_size = buffer.size();

    // Free space depends on the buffer's capacity vs current size
    // If capacity is greater than size, we have free space
    info.free_space = buffer.capacity() - buffer.size();

    return info;
}
```

Alternative implementation if you need to track read/write positions separately:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

// Global variables to track read/write positions (if needed)
static size_t read_pos = 0;
static size_t write_pos = 0;

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Return pointer to current read position
    if (buffer.empty() || read_pos >= buffer.size()) {
        return nullptr;
    }
    return buffer.data() + read_pos;
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Return pointer to current write position
    if (buffer.empty() || write_pos >= buffer.capacity()) {
        return nullptr;
    }
    return buffer.data() + write_pos;
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    BufferInfo info;

    // Readable size is from read_pos to write_pos
    info.readable_size = (write_pos > read_pos) ? (write_pos - read_pos) : 0;

    // Free space is from write_pos to capacity
    info.free_space = (write_pos < buffer.capacity()) ? (buffer.capacity() - write_pos) : 0;

    return info;
}
```

The first implementation is simpler and treats the entire buffer as readable/writable. The second implementation maintains separate read and write positions, which is more typical for circular buffers or stream processing. Choose the one that best fits your use case with the Hexi library.

