struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Create a buffer adaptor for reading from the buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Read the header (uint32_t) using buffer_adaptor's read method
    uint32_t header = adaptor.read<uint32_t>();

    // Get the remaining data after reading the header
    auto remaining_data = adaptor.remaining();

    // Create a binary_stream from the remaining data
    hexi::binary_stream stream(remaining_data);

    // Use binary_stream's view method to get a view of the null-terminated string
    auto message_view = stream.view('\0');

    // Convert the view to string_view (excluding the null terminator)
    std::string_view message(reinterpret_cast<const char*>(message_view.data()), 
                            message_view.size());

    return MessagePacket{header, message};
}
