#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block allocator for uint32_t elements
    hexi::block_allocator<uint32_t, element_count> allocator;

    std::vector<uint32_t*> allocated_blocks;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Allocator capacity: " << element_count << " blocks\n\n";

    // Demonstrate allocation (internally uses pop() from free list)
    std::cout << "Step 1: Allocating blocks (pop() from free list):\n";
    for (size_t i = 0; i < 5; ++i) {
        uint32_t* block = allocator.allocate(1);
        *block = i + 1; // Initialize with some value
        allocated_blocks.push_back(block);
        std::cout << "Allocated block " << i + 1 << " at address: " << block 
                  << " with value: " << *block << "\n";
    }

    std::cout << "\nStep 2: Deallocating blocks in LIFO order (push() to free list):\n";
    // Deallocate in reverse order to demonstrate LIFO behavior
    while (!allocated_blocks.empty()) {
        uint32_t* block = allocated_blocks.back();
        std::cout << "Deallocating block at address: " << block 
                  << " with value: " << *block << "\n";
        allocator.deallocate(block, 1);
        allocated_blocks.pop_back();
    }

    std::cout << "\nStep 3: Re-allocating blocks (showing LIFO free list behavior):\n";
    // Allocate again - should get blocks in reverse order of deallocation
    // because push() adds to head and pop() removes from head (LIFO)
    for (size_t i = 0; i < 3; ++i) {
        uint32_t* block = allocator.allocate(1);
        std::cout << "Re-allocated block at address: " << block << "\n";
        allocated_blocks.push_back(block);
    }

    // Cleanup
    for (auto block : allocated_blocks) {
        allocator.deallocate(block, 1);
    }

    std::cout << "\nStep 4: Testing edge case - allocating beyond capacity:\n";
    try {
        std::vector<uint32_t*> many_blocks;
        for (size_t i = 0; i < element_count + 1; ++i) {
            many_blocks.push_back(allocator.allocate(1));
        }
        std::cout << "Unexpectedly allocated " << element_count + 1 << " blocks\n";

        // Cleanup if we somehow succeeded
        for (auto block : many_blocks) {
            allocator.deallocate(block, 1);
        }
    } catch (const std::bad_alloc& e) {
        std::cout << "Correctly caught bad_alloc when exceeding capacity: " 
                  << e.what() << "\n";
    }

    std::cout << "\n=== Demonstration Complete ===\n";
    std::cout << "Key observations:\n";
    std::cout << "- Free list is managed as LIFO (Last-In-First-Out)\n";
    std::cout << "- push() adds freed blocks to the head of the free list\n";
    std::cout << "- pop() removes blocks from the head of the free list\n";
    std::cout << "- This leads to cache-friendly allocation patterns\n";
}

// Optional: Add a main function to test the demonstration
/*
int main() {
    demonstrate_block_allocator_behavior<10>();
    return 0;
}
*/
```

This implementation demonstrates how the `block_allocator` internally manages its free list using `push()` and `pop()` operations, even though these methods are private. The key observations are:

1. **LIFO Behavior**: The free list operates as a stack (Last-In-First-Out)
2. **push()**: Called during `deallocate()` - adds the freed block to the head of the free list
3. **pop()**: Called during `allocate()` - removes and returns the block from the head of the free list
4. **Cache Efficiency**: This LIFO pattern tends to be cache-friendly as recently freed blocks are likely still in cache

The demonstration shows the allocation/deallocation pattern and how blocks are reused in reverse order of their deallocation, which is characteristic of the free list management.

