```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path, std::ios::in | std::ios::binary);

    if (!file.is_open()) {
        throw std::runtime_error("Failed to open file for reading: " + file_path.string());
    }

    // Get the actual readable size (don't read beyond file size)
    size_t actual_bytes_to_read = std::min(bytes_to_read, file.size());

    std::vector<uint8_t> buffer(actual_bytes_to_read);

    // Read data into the buffer
    file.read(reinterpret_cast<char*>(buffer.data()), actual_bytes_to_read);

    return buffer;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path, std::ios::in | std::ios::binary);

    if (!file.is_open()) {
        throw std::runtime_error("Failed to open file for preview: " + file_path.string());
    }

    // Save the current read position
    size_t original_position = file.tellg();

    // Get the actual preview size (don't read beyond file size)
    size_t actual_bytes_to_preview = std::min(bytes_to_preview, file.size() - original_position);

    std::vector<uint8_t> buffer(actual_bytes_to_preview);

    // Read data into the buffer without modifying the original position
    file.read(reinterpret_cast<char*>(buffer.data()), actual_bytes_to_preview);

    // Restore the original read position
    file.seekg(original_position);

    return buffer;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create a file_buffer object for writing (truncate existing file)
    hexi::file_buffer file(file_path, std::ios::out | std::ios::binary | std::ios::trunc);

    if (!file.is_open()) {
        throw std::runtime_error("Failed to open file for writing: " + file_path.string());
    }

    // Write the entire data buffer to the file
    file.write(reinterpret_cast<const char*>(data.data()), data.size());

    // Ensure data is flushed to disk
    file.flush();
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path, std::ios::in | std::ios::binary);

    if (!file.is_open()) {
        throw std::runtime_error("Failed to open file for size check: " + file_path.string());
    }

    // Return the size of the file
    return file.size();
}
