#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <stdexcept>

/**
 * @brief Preview the first N bytes of a file without advancing the read pointer
 * 
 * @param file_path Path to the file to preview
 * @param header_size Number of bytes to read from the file header
 * @return std::vector<uint8_t> Vector containing the header data
 * 
 * @throws std::runtime_error if the file cannot be opened or read
 */
std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Validate input parameters
    if (header_size == 0) {
        return {};
    }

    if (!std::filesystem::exists(file_path)) {
        throw std::runtime_error("File does not exist: " + file_path.string());
    }

    // Create and open file buffer
    hexi::file_buffer file;
    if (!file.open(file_path.string(), "rb")) {
        throw std::runtime_error("Cannot open file: " + file_path.string());
    }

    try {
        // Save current position
        size_t current_pos = file.tell();

        // Seek to beginning to read header
        file.seek(0, SEEK_SET);

        // Read header data
        std::vector<uint8_t> header_data(header_size);
        size_t bytes_read = file.read(reinterpret_cast<char*>(header_data.data()), header_size);

        // Restore original position
        file.seek(current_pos, SEEK_SET);

        // Resize to actual bytes read
        header_data.resize(bytes_read);

        return header_data;
    }
    catch (const std::exception& e) {
        throw std::runtime_error("Error reading file header: " + std::string(e.what()));
    }
}
```

