```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Determine how many bytes we can actually preview (limited by available data)
    size_t bytes_available = buffer.size();
    size_t bytes_to_copy = std::min(bytes_to_preview, bytes_available);

    // Create result vector with the appropriate size
    std::vector<uint8_t> result;
    result.reserve(bytes_to_copy);

    // Get the current read position without advancing it
    auto read_pos = buffer.begin();

    // Copy the data byte by byte
    for (size_t i = 0; i < bytes_to_copy; ++i) {
        result.push_back(static_cast<uint8_t>(*read_pos));
        ++read_pos;

        // Handle wrap-around if we reach the end of the buffer
        if (read_pos == buffer.end()) {
            read_pos = buffer.begin();
        }
    }

    return result;
}
```

