```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/buffer_read.h>
#include <vector>
#include <cstdint>

std::size_t find_byte_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::byte value) {
    // Create a buffer reader starting from the beginning
    hexi::pmc::buffer_read reader(buffer, 0);

    // Read through the buffer until we find the target byte
    while (reader.remaining() > 0) {
        std::size_t current_pos = reader.position();
        std::byte current_byte = reader.read_byte();

        if (current_byte == value) {
            return current_pos;  // Return the position where we found the byte
        }
    }

    return hexi::pmc::buffer_read::npos;  // Not found
}

std::size_t find_delimiter_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::byte delimiter) {
    // This is essentially the same as find_byte_in_buffer but with a more descriptive name
    // for delimiter use cases (like null terminators, separators, etc.)
    return find_byte_in_buffer(buffer, delimiter);
}

bool check_buffer_contains(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, std::byte value) {
    // Use find_byte_in_buffer and check if the result is not npos
    return find_byte_in_buffer(buffer, value) != hexi::pmc::buffer_read::npos;
}
```

