    // Create a buffer with enough capacity for the input data
    std::vector<uint8_t> buffer(input_data.size());

    // Create buffer_write_adaptor
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer.data(), buffer.size());

    // Check available space before writing
    if (write_adaptor.free() >= input_data.size()) {
        // Write data to the buffer
        write_adaptor.write(input_data.data(), input_data.size());
    }

    // Create buffer_read_adaptor to read back the data
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer.data(), buffer.size());

    // Check readable size
    std::size_t readable_size = read_adaptor.size();
    std::vector<uint8_t> result(readable_size);

    // Read data back from the buffer
    if (readable_size > 0) {
        read_adaptor.read(result.data(), readable_size);
    }

    return result;
