std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Calculate total size needed
    std::size_t total_size = 0;
    for (const auto& chunk : chunks) {
        total_size += chunk.size();
    }

    // Create buffer and write adaptor
    std::vector<uint8_t> buffer(total_size);
    hexi::pmc::buffer_write_adaptor adaptor(buffer.data(), buffer.size());

    // Write each chunk separately
    for (const auto& chunk : chunks) {
        // Check available space before each write
        std::size_t free_space = adaptor.free();
        if (free_space >= chunk.size()) {
            adaptor.write(chunk.data(), chunk.size());
        }
    }

    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    std::vector<uint8_t> result;

    // Create read adaptor
    hexi::pmc::buffer_read_adaptor adaptor(buffer.data(), buffer.size());

    // Read data in chunks until buffer is empty
    while (adaptor.size() > 0) {
        // Determine how much to read in this chunk
        std::size_t read_size = std::min(chunk_size, adaptor.size());
        std::vector<uint8_t> chunk(read_size);

        // Read partial data
        adaptor.read(chunk.data(), read_size);

        // Append to result
        result.insert(result.end(), chunk.begin(), chunk.end());

        // Check remaining data after each read
        std::size_t remaining = adaptor.size();
        if (remaining == 0) {
            break;
        }
    }

    return result;
}
