            // Use read() to consume the data (including the first byte we peeked at)
            result.resize(data_size);
            adaptor.read(result.data(), data_size);
        } else {
            // If not enough data, just read what's available
            result.resize(adaptor.remaining());
            adaptor.read(result.data(), adaptor.remaining());
        }
    } else {
        // If condition not met, we don't read anything beyond the peek
        // The read cursor remains at position 0 since we only used copy()
    }

    return result;
}

